sql:
SELECT tower_name, floor_num
FROM towers
WHERE (tower_area_id BETWEEN 1 AND 10 OR is_active = 1) AND difficulty_level = 5;

SELECT tower_name, team_exp
FROM towers
WHERE team_exp = (SELECT MAX(team_exp) FROM towers);

SELECT enemy_name
FROM enemies
WHERE is_boss = 1;

SELECT towers.tower_name, rewards.reward_name
FROM towers
INNER JOIN rewards ON towers.tower_id = rewards.tower_id;

SELECT tower_name, COUNT(tower_name) AS tower_count 
FROM towers 
GROUP BY tower_name;

SELECT player_level, player_stamina, player_team_exp
FROM player_progress
WHERE player_id = 'Desired Player ID';

SELECT SUM(stamina) AS total_stamina, SUM(team_exp) AS total_team_exp
FROM player_progress
WHERE player_id = 1;

SELECT SUM(team_exp) AS total_team_exp
FROM towers
WHERE is_active = 1;

SELECT tower_name
FROM towers
WHERE is_active = 1 AND tower_id IN (SELECT tower_id FROM enemies WHERE is_boss = 1);

SELECT player_name, tower_id, floor_num, stamina, team_exp, chest_id, background, bg_position
FROM player_progress
WHERE player_id = 1 AND floor_num = 110;

SELECT tower_id, COUNT(enemy_id) AS total_enemies
FROM enemies
GROUP BY tower_id;

SELECT pp.player_name, t.tower_name, t.stamina, t.team_exp
FROM player_progress pp
INNER JOIN towers t ON pp.tower_id = t.tower_id;

SELECT player_name, player_level, player_gold 
FROM player_progress
ORDER BY player_level DESC;

SELECT enemy_name, enemy_health
FROM enemies
WHERE tower_id = (SELECT tower_id FROM player_progress WHERE player_id = 0);

SELECT reward_name, reward_description
FROM rewards
ORDER BY reward_name;

SELECT player_name, SUM(team_exp) AS total_team_exp
FROM player_progress
GROUP BY player_name;
